{
    "level": "B1",
    "intro": "W tym temacie nauczysz się rozróżniać <strong>another, other, the other</strong> oraz <strong>others / the others</strong>.",
    "rules": [
        {
            "label": "JESZCZE JEDEN",
            "color": "emerald",
            "text": "<strong>Another</strong> = jeszcze jeden albo inny pojedynczy przedmiot.",
            "example": "Can I have another coffee?"
        },
        {
            "label": "INNE / DODATKOWE",
            "color": "blue",
            "text": "<strong>Other</strong> używamy z liczbą mnogą albo z rzeczownikiem niepoliczalnym.",
            "example": "other people / other information"
        },
        {
            "label": "TEN DRUGI / POZOSTAŁY",
            "color": "amber",
            "text": "<strong>The other</strong> = ten drugi / ten, który został.",
            "example": "One bag is mine, and the other bag is yours."
        }
    ]
}

{
    "title": "1. Główne różnice",
    "intro": "Zobacz, która forma pasuje do którego typu rzeczownika.",
    "items": [
        {
            "label": "jeden przedmiot",
            "title": "another + singular noun",
            "subtitle": "another day, another cup, another idea"
        },
        {
            "label": "inne / dodatkowe",
            "title": "other + plural / uncountable noun",
            "subtitle": "other books, other people, other information"
        },
        {
            "label": "konkretny drugi",
            "title": "the other + singular noun",
            "subtitle": "the other hand, the other room"
        },
        {
            "label": "bez rzeczownika",
            "title": "others / the others",
            "subtitle": "Some are ready; the others are late."
        }
    ]
}

{
    "title": "2. Kiedy używać każdej formy",
    "sections": [
        {
            "label": "Another = jeszcze jeden",
            "color": "emerald",
            "description": "<strong>Another</strong> łączy się z rzeczownikiem w liczbie pojedynczej i często znaczy „jeszcze jeden” albo „inny”.",
            "examples": [
                {
                    "en": "Can I have another sandwich?",
                    "ua": "Czy mogę dostać jeszcze jedną kanapkę?"
                },
                {
                    "en": "Let us try another method.",
                    "ua": "Spróbujmy innej metody."
                },
                {
                    "en": "She stayed for another hour.",
                    "ua": "Została jeszcze na godzinę."
                }
            ]
        },
        {
            "label": "Other = inne / dodatkowe",
            "color": "blue",
            "description": "<strong>Other</strong> stoi przed rzeczownikiem w liczbie mnogiej albo niepoliczalnym.",
            "examples": [
                {
                    "en": "Other students were already inside.",
                    "ua": "Inni studenci byli już w środku."
                },
                {
                    "en": "Do you have any other questions?",
                    "ua": "Czy masz jeszcze jakieś inne pytania?"
                },
                {
                    "en": "We need other information.",
                    "ua": "Potrzebujemy innych informacji."
                }
            ]
        },
        {
            "label": "The other / the others = pozostały / pozostali",
            "color": "amber",
            "description": "<strong>The other</strong> oznacza konkretny drugi albo ostatni jeden, a <strong>the others</strong> — resztę grupy.",
            "examples": [
                {
                    "en": "I have two keys. One is old and the other is new.",
                    "ua": "Mam dwa klucze. Jeden jest stary, a drugi nowy."
                },
                {
                    "en": "Some students passed, but the others failed.",
                    "ua": "Niektórzy studenci zdali, ale pozostali nie."
                },
                {
                    "en": "This side is clean. The other side is dirty.",
                    "ua": "Ta strona jest czysta. Tamta / druga strona jest brudna."
                }
            ],
            "note": "Bez rzeczownika używamy <strong>others / the others</strong>."
        }
    ]
}

{
    "title": "3. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Another z liczbą mnogą.",
            "wrong": "another books",
            "right": "✅ <span class=\"font-mono\">other books</span> / <span class=\"font-mono\">another book</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Other bez rzeczownika, gdy trzeba others.",
            "wrong": "Some students are here, and other are late.",
            "right": "✅ <span class=\"font-mono\">Some students are here, and others are late.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Brak the przy konkretnym kontraście.",
            "wrong": "One shoe is black, other shoe is brown.",
            "right": "✅ <span class=\"font-mono\">One shoe is black, the other shoe is brown.</span>"
        }
    ]
}

{
    "title": "4. Krótkie podsumowanie",
    "items": [
        "<strong>Another</strong> = jeszcze jeden / inny jeden przedmiot.",
        "<strong>Other</strong> = inne albo dodatkowe rzeczy / osoby; łączy się z liczbą mnogą albo rzeczownikiem niepoliczalnym.",
        "<strong>The other</strong> = konkretny drugi albo ten pozostały.",
        "<strong>Others / the others</strong> używamy bez rzeczownika.",
        "Zadaj sobie pytanie: czy chodzi o jeszcze jeden, o inne ogólnie, czy o konkretny pozostały element?"
    ]
}

